      total_score <= '0;
    end else begin
      total_score <= total_score_comb;
    end
  end

  // Stage 3: score to weight mapping
  always_comb begin
    if (total_score < TAU_FP_0) begin
      w_out = W_SET_0;
    end else if (total_score < TAU_FP_1) begin
      w_out = W_SET_1;
    end else if (total_score < TAU_FP_2) begin
      w_out = W_SET_2;
    end else if (total_score < TAU_FP_3) begin
      w_out = W_SET_3;
    end else if (total_score < TAU_FP_4) begin
      w_out = W_SET_4;
    end else if (total_score < TAU_FP_5) begin
      w_out = W_SET_5;
    end else if (total_score < TAU_FP_6) begin
      w_out = W_SET_6;
    end else if (total_score < TAU_FP_7) begin
      w_out = W_SET_7;
    end else begin
      w_out = W_SET_8;
    end
  end

endmodule
